module top_module(
  input [3:0] A,
  input [3:0] B,
  input [1:0] op,
  output reg neq
);always @ (A, B, op) begin
    case(op)
      2'b00: neq = (A == B);
      2'b01: neq = (A > B);
      2'b10: neq = (A < B);
      2'b11: neq = (A != B);
      default: neq = 0;
    endcase
  end

endmodule
